/* ───────── Harita Veri Dosyası ─────────
   PLACES ve ROUTES hem client (harita) hem server (SEO/JSON-LD) tarafından kullanılır.
*/

export type PlaceType = "müze" | "galeri" | "konser" | "tiyatro" | "tarihi" | "edebiyat" | "miras" | "doğa" | "gastronomi" | "mimari";

export type EraType = "paleolitik" | "hitit" | "frig" | "roma" | "selcuklu" | "osmanli" | "cumhuriyet";

export const ERA_LABELS: Record<EraType, string> = {
  paleolitik: "Paleolitik & Tarihöncesi",
  hitit: "Hitit",
  frig: "Frig",
  roma: "Roma & Bizans",
  selcuklu: "Selçuklu",
  osmanli: "Osmanlı",
  cumhuriyet: "Cumhuriyet",
};

export const ERA_ORDER: EraType[] = ["paleolitik", "hitit", "frig", "roma", "selcuklu", "osmanli", "cumhuriyet"];

export type CulturePlace = {
  lat: number;
  lng: number;
  type: PlaceType;
  name: string;
  desc: string;
  longDesc?: string;
  funFacts?: string[];
  image?: string;
  era?: EraType | EraType[];
  minZoom?: number;
  venueAliases?: string[];
  hours?: string;
  admission?: string;
  tips?: string[];
};

export type RouteStop = {
  lat: number;
  lng: number;
  name: string;
  story: string;
};

export type Route = {
  id: number;
  title: string;
  icon: string;
  duration: string;
  color: string;
  desc: string;
  longDesc?: string;
  tips?: string[];
  bestTime?: string;
  difficulty?: "kolay" | "orta" | "zor";
  stops: RouteStop[];
  fx?: "xray" | "grayscale" | "noir" | "neon" | "rock";
  nightOnly?: boolean;
};

